



import { Component, OnInit } from "@angular/core";
import { DataService } from "./../../../../shared/services/data.service";
import { AppConfig } from "./../../../../app.config";
import { PageModel } from "./../../../../models/page.model";
import { Router } from "@angular/router";
import { NgbModal, ModalDismissReasons } from "@ng-bootstrap/ng-bootstrap";
import { ViewCashKanikeComponent } from './../view-cash-kanike/view-cash-kanike.component';
import { NxService } from "./../../../../shared/nx-library/nx.service";

@Component({
  selector: 'app-list-cash-kanike',
  templateUrl: './list-cash-kanike.component.html',
  styleUrls: ['./list-cash-kanike.component.css']
})
export class ListCashKanikeComponent implements OnInit {
  CashKanikeList: any[] = [];
  page: PageModel = new PageModel("firstName");
  searchText: string;
  currentUser: any;
  hideaddbooking: boolean;

  constructor(
    private router: Router,
    private ds: DataService,
    private modalService: NgbModal,
    private nx: NxService
  ) {}

  ngOnInit() {
    const _user = localStorage.getItem("current-user");
    this.currentUser = JSON.parse(_user);

    if (this.currentUser.email != "adkabbalamma@gmail.com" && this.currentUser.email != "askabbalamma@gmail.com") {
      this.hideaddbooking = false;
    } 

    this.getCashKanikeList();
  }

  onRouteChange(path) {
    this.router.navigate([path]);
  }

  onSort(item) {}



  onViewDetails(item) {
    const modalRef = this.modalService.open(ViewCashKanikeComponent, {
      size: "lg"
    });
    modalRef.componentInstance.modelData = item;
    modalRef.result
      .then(result => {
        if (result) {
          console.log("Hello");
        }
      })
      .catch(error => {
        console.log(error);
      });
  }

  private getCashKanikeList() {
    const req = {
      url: AppConfig.Api.CashKanike.GetAll,
      params: {
        currentPage: this.page.currentPage,
        itemPerPage: this.page.itemPerPage,
        sort: this.page.sort,
        sortBy: this.page.sortBy
      }
    };
    this.ds.post(req).subscribe((res: any) => {
      if (res.status) {
        this.CashKanikeList = res.data;
        this.page.totalItems = res.totalItems;
      } else {
      }
    });
  }
}
