import { Component, OnInit } from "@angular/core";
import { DataService } from "../../../shared/services/data.service";
import { AppConfig } from "../../../app.config";
import { PageModel } from "../../../models/page.model";
import { Router } from "@angular/router";

@Component({
  selector: "app-donation",
  templateUrl: "./donation.component.html",
  styleUrls: ["./donation.component.css"]
})
export class DonationComponent implements OnInit {
  donationList: any[] = [];
  page: PageModel = new PageModel("firstName");
  searchText: string;

  constructor(private router: Router, private ds: DataService) {}

  ngOnInit() {
    this.getDonationList();
  }

  onRouteChange(path) {
    this.router.navigate([path]);
  }

  onSort(item) {}

  private getDonationList() {
    const req = {
      url: AppConfig.Api.Donation.GetAll,
      params: {
        currentPage: this.page.currentPage,
        itemPerPage: this.page.itemPerPage,
        sort: this.page.sort,
        sortBy: this.page.sortBy
      }
    };
    this.ds.post(req).subscribe((res: any) => {
      if (res.status) {
        this.donationList = res.data;
        this.page.totalItems = res.totalItems;
      } else {
      }
    });
  }
}
