import { Component, OnInit, Renderer2 } from "@angular/core";
import { Router } from "@angular/router";
import { ActiveUserService } from "src/app/shared/services/active-user.service";
import { ActiveUserModel } from "src/app/models/active-user.model";

@Component({
  selector: "app-admin",
  templateUrl: "./admin.component.html",
  styleUrls: ["./admin.component.css"]
})
export class AdminComponent implements OnInit {
  currentUser: any;
  isSideBarDis: boolean;
  activeUserModel: ActiveUserModel;
  hideElement: boolean;
  hideResouce: boolean;
  hideaddbooking: boolean;
  _currentUser: any;

  constructor(
    private router: Router,
    private activeUser: ActiveUserService,
    private renderer: Renderer2
  ) {
    this.activeUserModel = new ActiveUserModel();
  }

  ngOnInit() {
    this.currentUser = this.activeUser.getUser();
    this.isSideBarDis = true;
    this.hideResouce = true;
    this.hideaddbooking = true;

    const _user = localStorage.getItem("current-user");
    this._currentUser = JSON.parse(_user);

    if (this._currentUser.email == "adkabbalamma@gmail.com") {
      this.hideResouce = false;
    } else if (this._currentUser.email == "askabbalamma@gmail.com") {
      this.hideResouce = false;
    } else if (this._currentUser.email == "shashi.rsb@hotmail.com") {
      this.hideaddbooking = true;
      this.hideResouce = true;
    } else {
      this.hideaddbooking = false;
    }

  }

  onLogoutClick() {
    this.activeUser.clearUser();
    this.onRouteChange("auth/signin");
  }

  onRouteChange(path: string) {
    this.router.navigate([path]);
  }

  toggleSideBar() {

    this.isSideBarDis = this.isSideBarDis ? false : true;
    this.hideElement = this.hideElement ? false : true;
    if (this.isSideBarDis) {
      this.renderer.removeClass(document.body, "sidenav-toggled");
    } else {
      this.renderer.addClass(document.body, "sidenav-toggled");
    }
  }
}
