
import { Component, OnInit } from "@angular/core";
import { DataService } from "./../../../../shared/services/data.service";
import { AppConfig } from "./../../../../app.config";
import { PageModel } from "./../../../../models/page.model";
import { Router } from "@angular/router";
import { NgbModal, ModalDismissReasons } from "@ng-bootstrap/ng-bootstrap";
import { ViewUtsavaMurthyComponent } from "./../view-utsava-murthy/view-utsava-murthy.component";
import { NxService } from "./../../../../shared/nx-library/nx.service";

@Component({
  selector: 'app-list-utsava-murthy',
  templateUrl: './list-utsava-murthy.component.html',
  styleUrls: ['./list-utsava-murthy.component.css']
})
export class ListUtsavaMurthyComponent implements OnInit {
  kanikeList: any[] = [];
  page: PageModel = new PageModel("firstName");
  searchText: string;

  constructor(
    private router: Router,
    private ds: DataService,
    private modalService: NgbModal,
    private nx: NxService
  ) {}

  ngOnInit() {
    this.getUtsavaMurthyList();
  }

  onRouteChange(path) {
    this.router.navigate([path]);
  }

  onSort(item) {}



  onViewDetails(item) {
    const modalRef = this.modalService.open(ViewUtsavaMurthyComponent, {
      size: "lg"
    });
    modalRef.componentInstance.modelData = item;
    modalRef.result
      .then(result => {
        if (result) {
          console.log("Hello");
        }
      })
      .catch(error => {
        console.log(error);
      });
  }

  private getUtsavaMurthyList() {
    const req = {
      url: AppConfig.Api.UtsavaMurthy.GetAll,
      params: {
        currentPage: this.page.currentPage,
        itemPerPage: this.page.itemPerPage,
        sort: this.page.sort,
        sortBy: this.page.sortBy
      }
    };
    this.ds.post(req).subscribe((res: any) => {
      if (res.status) {
        this.getUtsavaMurthyList = res._finalfirstResult;
        this.page.totalItems = res.totalItems;
      } else {
      }
    });
  }
}
