import { Component, OnInit } from "@angular/core";
import { DataService } from "../../../../shared/services/data.service";
import { AppConfig } from "../../../../app.config";
import { PageModel } from "../../../../models/page.model";
import { Router } from "@angular/router";
import { NgbModal, ModalDismissReasons } from "@ng-bootstrap/ng-bootstrap";
import { ViewBookingComponent } from "./../view-booking/view-booking.component";
import { NxService } from "../../../../shared/nx-library/nx.service";

@Component({
  selector: 'app-darshan-list',
  templateUrl: './darshan-list.component.html',
  styleUrls: ['./darshan-list.component.css']
})
export class DarshanListComponent implements OnInit {
  bookingList: any[] = [];
  page: PageModel = new PageModel("firstName");
  searchText: string;

  constructor(
    private router: Router,
    private ds: DataService,
    private modalService: NgbModal,
    private nx: NxService
  ) {}

  ngOnInit() {
    this.getHundiList();
  }

  onRouteChange(path) {
    this.router.navigate([path]);
  }

  onSort(item) {}

  onPrintClick(item) {
		var localbookingDate = new Date(item.bookingDate);
		var formatbookingDate = localbookingDate.getDate() + "/" + (localbookingDate.getMonth()+1) + "/" + localbookingDate.getFullYear();
		var localcreatedAt = new Date(item.createdAt);
		var formatcreatedAt = localcreatedAt.getDate() + "/" + (localcreatedAt.getMonth()+1) + "/" + localcreatedAt.getFullYear() + " "+ localcreatedAt.getHours() + ":"+ localcreatedAt.getMinutes() + ":"+ localcreatedAt.getSeconds();

		var serviceType = null;
		var serviceAmount = null;
		if(item.bookingFor == "darshan" ) {
          serviceType = item.darshanType.title;
		  serviceAmount=item.darshanType.price;
		} else if(item.bookingFor == "seva" ) {
		  serviceType = item.sevaType.title;
		  serviceAmount=item.sevaType.price;
		}


		var qstring = "Booking_Id=" + item.bookingId + "&Service=" + serviceType + "&Booking_Date=" + formatbookingDate+ "&Created_Date=" + formatcreatedAt + "&Booking_From=" + item.bookingStartTime +"&Booking_To=" + item.bookingEndTime +"&Booking_Amount=" + serviceAmount + "&Devotees=" + item.numberOfDevotees +"&Payment_Type=" + item.paymentType +"&Person_Name=" + item.bookingPersonName + "&Mobile=" + item.bookingPersonMobile + "&Booked_from=" + item.bookingBy;

		//var qstring = "Booking_Id=BK20180720002436170&Service=vip_darshan&Booking_Date=26-08-2018&Created_Date=20-08-2018&Booking_From=16&Booking_To=17&Booking_Amount=100&Devotees=1&Payment_Type=cash&Person_Name=shashi&Mobile=7619453389&Booked_from=online";
		window.open("http://localhost:3000/sample.html?"+qstring, "_blank", "resize=no,directories=no,menubar=no,status=no,titlebar=no,toolbar=no, width=500, height=200, top=25, left=25, right=25");

  }

  onViewDetails(item) {
    const modalRef = this.modalService.open(ViewBookingComponent, {
      size: "lg"
    });
    modalRef.componentInstance.modelData = item;
    modalRef.result
      .then(result => {
        if (result) {
          console.log("Hello");
        }
      })
      .catch(error => {
        console.log(error);
      });
  }

  private getHundiList() {
    const req = {
      url: AppConfig.Api.Booking.GetAllDarshanBooking,
      params: {
        currentPage: this.page.currentPage,
        itemPerPage: this.page.itemPerPage,
        sort: this.page.sort,
        sortBy: this.page.sortBy
      }
    };
    this.ds.post(req).subscribe((res: any) => {
      if (res.status) {
        this.bookingList = res.data.collection;
        this.page.totalItems = res.data.totalItem;
      } else {
      }
    });
  }

  onSelectPage(value: any) {
    this.page.currentPage = +value;
    this.getHundiList();
  }

  onPreClick(value: any) {
    if (value) {
      this.page.currentPage--;
      this.getHundiList();
    }
  }

  onNextClick(value: any) {
    if (value) {
      this.page.currentPage++;
      this.getHundiList();
    }
  }

  onChangeItemPerPage(value: any) {
    this.page.currentPage = 1;
    this.page.itemPerPage = +value;
    this.getHundiList();
  }
}
