import { AppEnums } from "../shared/enums/enum.config";
import { AppConfig } from "../app.config";

export class PageModel {
  constructor(
    public sortBy: string,
    public itemPerPage?: number,
    public displayPageCount?: number,
    public sort?: string,
    public currentPage?: number,
    public totalItems?: number
  ) {
    this.itemPerPage = AppConfig.Pagination.ItemPerPage || 10;
    this.displayPageCount = AppConfig.Pagination.DisplayPageCount || 7;
    this.currentPage = 1;
    this.totalItems = 0;
    this.sort = AppEnums.Sort.Asc;
  }
}
