import { Component, OnInit } from "@angular/core";
import { Router, ActivatedRoute } from "@angular/router";
import {
  FormGroup,
  FormBuilder,
  FormControl,
  Validators
} from "@angular/forms";
import { DataService } from "../../../../shared/services/data.service";
import { NxService } from "../../../../shared/nx-library/nx.service";
import { AppConfig } from "../../../../app.config";

@Component({
  selector: 'app-edit-darshan-type',
  templateUrl: './edit-darshan-type.component.html',
  styleUrls: ['./edit-darshan-type.component.css']
})
export class EditDarshanTypeComponent implements OnInit {

  darshanTypeForm: FormGroup;
  vm = AppConfig.Message.Validation;
  isEditMode: boolean;
  constructor(
    private fb: FormBuilder,
    private ds: DataService,
    private router: Router,
    private nx: NxService,
    private route: ActivatedRoute
  ) {
    this.initializeForm();
  }

  ngOnInit() {
    this.isEditMode = false;
    this.route.params.subscribe(params => {
      const _id = params["id"];
      this.getInitialData(_id);
      console.log(params["id"]);
    });
  }

  getInitialData(id) {
    const req = {
      url: AppConfig.Api.DarshanType.GetById,
      params: {
        id: id
      }
    };
    this.ds.getById(req).subscribe((res: any) => {
      if (res.status) {
        this.SetFormData(res.data);
        this.nx.message.success("Get Data Successfully.");
      } else {
        this.nx.message.error(res.message);
      }
    });
  }

  onEditClick() {
    this.isEditMode = true;
  }

  onCancelClick() {
    this.isEditMode = false;
  }

  onSubmitForm() {
    if (!this.darshanTypeForm.valid) {
      this.validateForm(this.darshanTypeForm);
    } else if (this.darshanTypeForm.valid) {
      const req = {
        url: AppConfig.Api.DarshanType.Update,
        params: this.darshanTypeForm.value
      };
      this.ds.post(req).subscribe((res: any) => {
        if (res.status) {
          this.nx.message.success("Update Darshan Type Successfully.");
          this.onResetForm();
        } else {
          this.nx.message.error(res.message);
        }
      });
    }
  }

  onResetForm() {
    this.darshanTypeForm.reset();
    this.onRouteChange('admin/darshan-type');
  }

  onRouteChange(path) {
    this.router.navigate([path]);
  }

  get title() {
    return this.darshanTypeForm.get("title");
  }

  get price() {
    return this.darshanTypeForm.get("price");
  }

  get allowed() {
    return this.darshanTypeForm.get("allowed");
  }

  get description() {
    return this.darshanTypeForm.get("description");
  }

  private initializeForm() {
    this.darshanTypeForm = this.fb.group({
      _id: ["", Validators.required],
      title: ["", Validators.required],
      price: [0, Validators.required],
      allowed: [0, Validators.required],
      description: ""
    });
  }

  private SetFormData(model: any) {
    this.darshanTypeForm.patchValue({
      _id: model._id,
      title: model.title,
      price: model.price,
      allowed: model.allowed,
      description: model.description,
    });
  }

  private validateForm(formGroup: FormGroup) {
    Object.keys(formGroup.controls).forEach(filed => {
      const control = formGroup.get(filed);
      if (control instanceof FormControl) {
        control.markAsTouched({ onlySelf: true });
      }
    });
  }

}
