import { Component, OnInit } from "@angular/core";
import {
  FormGroup,
  FormBuilder,
  Validators,
  FormControl
} from "@angular/forms";
import { DataService } from "../../../../shared/services/data.service";
import { Router, ActivatedRoute } from "@angular/router";
import { NxService } from "../../../../shared/nx-library/nx.service";
import { AppConfig } from "../../../../app.config";
import { NgbModal, ModalDismissReasons, NgbDatepickerConfig} from "@ng-bootstrap/ng-bootstrap";
import { ActiveUserService } from "src/app/shared/services/active-user.service";
import { ActiveUserModel } from "src/app/models/active-user.model";

@Component({
  selector: 'app-add-block-booking',
  templateUrl: './add-block-booking.component.html',
  styleUrls: ['./add-block-booking.component.css']
})
export class AddBlockBookingComponent implements OnInit {

  bookingForm: FormGroup;
  darshanTypeList: any[];
  sevaTypeList: any[];
  currentUser: ActiveUserModel;
  blockBookingDate: any;

  constructor(
    private fb: FormBuilder,
    private ds: DataService,
    private router: Router,
    private nx: NxService,
    private activatedRoute: ActivatedRoute,
    private ngbDatepickerConfig: NgbDatepickerConfig,
    private activeUser: ActiveUserService
  ) {
    ngbDatepickerConfig.minDate = this.nx.date.getMinDateObj();
    ngbDatepickerConfig.maxDate = this.nx.date.getMaxDateObj(0, 6, 0);
    this.currentUser = new ActiveUserModel();
    this.initializeForm();
  }

  ngOnInit() {
    this.currentUser = this.activeUser.getUser();
    this.userId.setValue(this.currentUser._id);
    this.getDarshanTypeList();
    this.getSevaTypeList();
  }

  onSubmitForm() {
    this.bookingBlockDate.setValue(this.nx.date.getObjToDateString(this.blockBookingDate));

    if (!this.bookingForm.valid) {
      this.validateForm(this.bookingForm);
    } else if (this.bookingForm.valid) {
      const req = {
        url: AppConfig.Api.BlockBooking.Create,
        params: this.bookingForm.value
      };
      this.ds.post(req).subscribe((res: any) => {
        if (res.status) {
          this.onRouteChange('admin/block-booking');
          this.nx.message.success("Block booking successfully.");
        } else {
          this.nx.message.error(res.message);
        }
      });
    }
  }

  onRouteChange(path) {
    this.router.navigate([path]);
  }

  getDarshanTypeList() {
    const req = {
      url: AppConfig.Api.Lookup.DarshanType,
      params: null
    };
    this.ds.get(req).subscribe((res: any) => {
      if (res.status) {
        this.darshanTypeList = res.data;
      } else {
        this.nx.message.error(res.message);
      }
    });
  }

  getSevaTypeList() {
    const req = {
      url: AppConfig.Api.Lookup.SevaType,
      params: null
    };
    this.ds.get(req).subscribe((res: any) => {
      if (res.status) {
        this.sevaTypeList = res.data;
      } else {
        this.nx.message.error(res.message);
      }
    });
  }

  get bookingBlockType() {
    return this.bookingForm.get("bookingBlockType");
  }

  get bookingBlockFor() {
    return this.bookingForm.get("bookingBlockFor");
  }

  get userId() {
    return this.bookingForm.get("userId");
  }

  get bookingBlockDate() {
    return this.bookingForm.get("bookingBlockDate");
  }

  private initializeForm() {
    this.bookingForm = this.fb.group({
      userId: ["", Validators.required],
      darshanType: null,
      sevaType: null,
      bookingBlockType: ["", Validators.required],
      bookingBlockFor: ["darshan", Validators.required],
      bookingBlockDate: ["", Validators.required],
      bookingBlockStartTime: "0",
      bookingBlockEndTime: "0",
      description: ""
    });
  }

  private validateForm(formGroup: FormGroup) {
    Object.keys(formGroup.controls).forEach(filed => {
      const control = formGroup.get(filed);
      if (control instanceof FormControl) {
        control.markAsTouched({ onlySelf: true });
      }
    });
  }

}
