import { Component, OnInit } from "@angular/core";
import { Router, ActivatedRoute } from "@angular/router";
import {
  FormGroup,
  FormBuilder,
  FormControl,
  Validators
} from "@angular/forms";
import { DataService } from "../../../../shared/services/data.service";
import { NxService } from "../../../../shared/nx-library/nx.service";
import { AppConfig } from "../../../../app.config";

@Component({
  selector: "app-edit-donation-type",
  templateUrl: "./edit-donation-type.component.html",
  styleUrls: ["./edit-donation-type.component.css"]
})
export class EditDonationTypeComponent implements OnInit {
  donationTypeForm: FormGroup;
  vm = AppConfig.Message.Validation;
  isEditMode: boolean;
  constructor(
    private fb: FormBuilder,
    private ds: DataService,
    private router: Router,
    private nx: NxService,
    private route: ActivatedRoute
  ) {
    this.initializeForm();
  }

  ngOnInit() {
    this.isEditMode = false;
    this.route.params.subscribe(params => {
      const _id = params["id"];
      this.getInitialData(_id);
      console.log(params["id"]);
    });
  }

  getInitialData(id) {
    const req = {
      url: AppConfig.Api.DonationType.GetById,
      params: {
        id: id
      }
    };
    this.ds.getById(req).subscribe((res: any) => {
      if (res.status) {
        this.SetFormData(res.data);
        this.nx.message.success("Get Data Successfully.");
      } else {
        this.nx.message.error(res.message);
      }
    });
  }

  onEditClick() {
    this.isEditMode = true;
  }

  onCancelClick() {
    this.isEditMode = false;
  }

  onSubmitForm() {
    if (!this.donationTypeForm.valid) {
      this.validateForm(this.donationTypeForm);
    } else if (this.donationTypeForm.valid) {
      const req = {
        url: AppConfig.Api.DonationType.Update,
        params: this.donationTypeForm.value
      };
      this.ds.post(req).subscribe((res: any) => {
        if (res.status) {
          this.nx.message.success("Block booking successfully.");
          this.onResetForm();
        } else {
          this.nx.message.error(res.message);
        }
      });
    }
  }

  onResetForm() {
    this.donationTypeForm.reset();
    this.onRouteChange("admin/donation-type");
  }

  onRouteChange(path) {
    this.router.navigate([path]);
  }

  get title_en() {
    return this.donationTypeForm.get("title_en");
  }
  get title_kan() {
    return this.donationTypeForm.get("title_kan");
  }

  get description_en() {
    return this.donationTypeForm.get("description_en");
  }
  get description_kan() {
    return this.donationTypeForm.get("description_kan");
  }

  get hasCardDonation() {
    return this.donationTypeForm.get("hasCardDonation");
  }

  get cardTitle_en() {
    return this.donationTypeForm.get("cardTitle_en");
  }
  get cardTitle_kan() {
    return this.donationTypeForm.get("cardTitle_kan");
  }

  get cardAmount() {
    return this.donationTypeForm.get("cardAmount");
  }

  get cardCause_en() {
    return this.donationTypeForm.get("cardCause_en");
  }
  get cardCause_kan() {
    return this.donationTypeForm.get("cardCause_kan");
  }

  get cardBenifits_en() {
    return this.donationTypeForm.get("cardBenifits_en");
  }
  get cardBenifits_kan() {
    return this.donationTypeForm.get("cardBenifits_kan");
  }

  private initializeForm() {
    this.donationTypeForm = this.fb.group({
      _id: ["", Validators.required],
      title_en: ["", Validators.required],
      title_kan: ["", Validators.required],
      description_en: "",
      description_kan: "",
      hasCardDonation: false,
      cardTitle_en: "",
      cardTitle_kan: "",
      cardAmount: 0,
      cardCause_en: "",
      cardCause_kan: "",
      cardBenifits_en: "",
      cardBenifits_kan: ""
    });
  }

  private SetFormData(model: any) {
    this.donationTypeForm.patchValue({
      _id: model._id,
      title_en: model.title_en,
      title_kan: model.title_kan,
      description_en: model.description_en,
      description_kan: model.description_kan,
      hasCardDonation: model.hasCardDonation,
      cardTitle_en: model.cardTitle_en,
      cardTitle_kan: model.cardTitle_kan,
      cardAmount: model.cardAmount,
      cardCause_en: model.cardCause_en,
      cardCause_kan: model.cardCause_kan,
      cardBenifits_en: model.cardBenifits_en,
      cardBenifits_kan: model.cardBenifits_kan
    });
  }

  private validateForm(formGroup: FormGroup) {
    Object.keys(formGroup.controls).forEach(filed => {
      const control = formGroup.get(filed);
      if (control instanceof FormControl) {
        control.markAsTouched({ onlySelf: true });
      }
    });
  }
}
