  onSubmitForm() {
    if (!this.hundiCollectioniAddForm.valid) {
      this.validateForm(this.hundiCollectioniAddForm);
    } else if (this.hundiCollectioniAddForm.valid) {
      const req = {
        url: AppConfig.Api.HundiCollection.Create,
        params: this.hundiCollectioniAddForm.value
      };
      this.ds.post(req).subscribe((res: any) => {
        if (res.status) {
          this.nx.message.success("Add Special Pooja Successfully.");
          this.onResetForm();
        } else {
          this.nx.message.error(res.message);
        }
      });
    }
  }

