  currentUserId: any;
  currentPersonName: any;


  constructor(private modalService: NgbModal,
    public _uploadService: UploadService,
    public uploadService: UploadService,
    private fb: FormBuilder,
    private ds: DataService,
    private router: Router,
    private nx: NxService
  ) {
    this.initializeForm();
  }

  ngOnInit() {

    const _user = localStorage.getItem("current-user");
    this.currentUser = JSON.parse(_user);
    this.userId.setValue(this.currentUser._id);
    this.currentPersonName = this.currentUser.firstName + " " + this.currentUser.lastName;
    this.bookingPersonName.setValue(this.currentPersonName);
  }

  get userId() {
    return this.utsavaMurthyAddForm.get("userId");
  }
  get bookingPersonName() {
    return this.utsavaMurthyAddForm.get("bookingPersonName");
  }

  get devoteeName() {
    return this.utsavaMurthyAddForm.get("devoteeName");
  }
  get devoteePhone() {
    return this.utsavaMurthyAddForm.get("devoteePhone");
  }
  get devoteeAddress() {
    return this.utsavaMurthyAddForm.get("devoteeAddress");
  }
  get idProofType() {
    return this.utsavaMurthyAddForm.get("idProofType");
  }
  get idProofNo() {
    return this.utsavaMurthyAddForm.get("idProofNo");
  }
  get utsavatype() {
    return this.utsavaMurthyAddForm.get("utsavatype");
  }
  get startDate() {
    return this.utsavaMurthyAddForm.get("startDate");
  }
  get endDate() {
    return this.utsavaMurthyAddForm.get("endDate");
  }




  onSubmitForm() {
    if (!this.utsavaMurthyAddForm.valid) {
      this.validateForm(this.utsavaMurthyAddForm);
    } else if (this.utsavaMurthyAddForm.valid) {
      const req = {
        url: AppConfig.Api.UtsavaMurthy.Create,
        params: this.utsavaMurthyAddForm.value
      };
      this.ds.post(req).subscribe((res: any) => {
        if (res.status) {
          this.nx.message.success("Add Utsava Murthy Successfully.");
          this.onResetForm();
        } else {
          this.nx.message.error(res.message);
        }
      });
    }
  }

