
import { Component, OnInit } from "@angular/core";
import { DataService } from "../../../../shared/services/data.service";
import { AppConfig } from "../../../../app.config";
import { PageModel } from "../../../../models/page.model";
import { Router } from "@angular/router";
import { NgbModal, ModalDismissReasons } from "@ng-bootstrap/ng-bootstrap";
import { ViewWebsiteAlbumComponent } from "../view-website-album/view-website-album.component";
import { NxService } from "../../../../shared/nx-library/nx.service";

@Component({
  selector: 'app-list-website-album',
  templateUrl: './list-website-album.component.html',
  styleUrls: ['./list-website-album.component.css']
})
export class ListWebsiteAlbumComponent implements OnInit {
  kanikeList: any[] = [];
  page: PageModel = new PageModel("firstName");
  searchText: string;

  constructor(
    private router: Router,
    private ds: DataService,
    private modalService: NgbModal,
    private nx: NxService
  ) {}

  ngOnInit() {
    this.getWebsiteAlbumList();
  }

  onRouteChange(path) {
    this.router.navigate([path]);
  }

  onSort(item) {}



  onViewDetails(item) {
    const modalRef = this.modalService.open(ViewWebsiteAlbumComponent, {
      size: "lg"
    });
    modalRef.componentInstance.modelData = item;
    modalRef.result
      .then(result => {
        if (result) {
          console.log("Hello");
        }
      })
      .catch(error => {
        console.log(error);
      });
  }

  private getWebsiteAlbumList() {
    const req = {
      url: AppConfig.Api.WebsiteAlbum.GetAll,
      params: {
        currentPage: this.page.currentPage,
        itemPerPage: this.page.itemPerPage,
        sort: this.page.sort,
        sortBy: this.page.sortBy
      }
    };
    this.ds.post(req).subscribe((res: any) => {
      if (res.status) {
        this.getWebsiteAlbumList = res.data.collection;
        console.log(this.getWebsiteAlbumList);
        this.page.totalItems = res.totalItems;
      } else {
      }
    });
  }
}
