
import { Component, OnInit } from "@angular/core";
import {
  FormGroup,
  FormBuilder,
  Validators,
  FormControl
} from "@angular/forms";
import { DataService } from "src/app/shared/services/data.service";
import { Router } from "@angular/router";
import { NxService } from "src/app/shared/nx-library/nx.service";
import { AppConfig } from "src/app/app.config";

@Component({
  selector: 'app-kanike-by-dates',
  templateUrl: './kanike-by-dates.component.html',
  styleUrls: ['./kanike-by-dates.component.css']
})
export class KanikeByDatesComponent implements OnInit {
  reportForm: FormGroup;
  collection: Array<any>;
  filterCollection: Array<any>;
  totalAmount: number;
  filterType: any;
  constructor(
    private _dataService: DataService,
    private _router: Router,
    private _fb: FormBuilder,
    private _nx: NxService
  ) {
    this.initilizeForm();
    this.collection = [];
    this.totalAmount = 0;
  }

  ngOnInit() { }

  onSubmitForm() {
    if (!this.reportForm.valid) {
      this.validateForm(this.reportForm);
    } else if (this.reportForm.valid) {
      const req = {
        url: AppConfig.Api.Report.KanikeReportByDate,
        params: this.reportForm.value
      };
      this._dataService.post(req).subscribe((res: any) => {
        if (res.status) {
          this.collection = res.data;
          this.filterCollection = this.collection;
          this.countTotal(this.filterCollection);
          this._nx.message.success("Get data successfully.");
        } else {
          this._nx.message.error("Error ! ");
        }
      });
    }
  }

  onfilterType(idType) {
    this.filterCollection = [];
    let _idType = idType.target.options[idType.target.options.selectedIndex].value;

    this.collection.forEach(element => {      
        if (_idType == element.kanikeType) {
          this.filterCollection.push(element);
          console.log(element);

      } else if (_idType == element.kanikeType) {
          this.filterCollection.push(element);
          console.log(element);
        }      
    });

    if(_idType == "all"){
      this.filterCollection = this.collection;
    }


  }

  countTotal(collection: any[]) {
    this.totalAmount = 0;
    for (let i = 0; i < collection.length; i++) {
      this.totalAmount = this.totalAmount + collection[i]['amountPaid']
    }
  }

  private initilizeForm() {
    this.reportForm = this._fb.group({
      startDate: ["", Validators.required],
      endDate: ["", Validators.required]
    });
  }

  private validateForm(formGroup: FormGroup) {
    Object.keys(formGroup.controls).forEach(filed => {
      const control = formGroup.get(filed);
      if (control instanceof FormControl) {
        control.markAsTouched({ onlySelf: true });
      }
    });
  }
}

