import { Component, OnInit, ViewChild } from '@angular/core';
import { NgbActiveModal, NgbModal } from '@ng-bootstrap/ng-bootstrap';
import { Router } from "@angular/router";
import {
  FormGroup,
  FormBuilder,
  Validators,
  FormControl,
  FormArray
} from "@angular/forms";
import { ActiveUserModel } from "../../../../models/active-user.model";
import { ActiveUserService } from "../../../../shared/services/active-user.service";
import { UploadService } from "./../../../../shared/services/upload.service";
import { UploadDialogComponent } from "../../../common/upload-dialog/upload-dialog.component";

import { forkJoin } from "rxjs/observable/forkJoin";

import { DataService } from "../../../../shared/services/data.service";
import { NxService } from "../../../../shared/nx-library/nx.service";
import { AppConfig } from "../../../../app.config";



@Component({
  selector: 'add-website-album',
  templateUrl: './add-website-album.component.html',
  styleUrls: ['./add-website-album.component.css']
})
export class AddWebsiteAlbumComponent implements OnInit {
  @ViewChild("file") file;
  public files: Set<File> = new Set();

  websiteAlbumForm: FormGroup;
  vm = AppConfig.Message.Validation;
  currentUser: ActiveUserModel = new ActiveUserModel();
  imagesPath: any[] = [];
  displayImagesPath: any[] = [];
  imageItems: FormArray;

  progress;
  canBeClosed = true;
  primaryButtonText = "Upload";
  showCancelButton = true;
  uploading = false;
  uploadSuccessful = false;
  imageAdded = false;
  currentUserId: any;
  currentPersonName: any;
  hideaddbooking: boolean;

  file_name: any;


  constructor(private modalService: NgbModal,
    public _uploadService: UploadService,
    public uploadService: UploadService,
    private fb: FormBuilder,
    private ds: DataService,
    private router: Router,
    private nx: NxService
  ) {
    this.initializeForm();
  }

  ngOnInit() {

    const _user = localStorage.getItem("current-user");
    this.currentUser = JSON.parse(_user);
    this.userId.setValue(this.currentUser._id);
    this.currentPersonName = this.currentUser.firstName + " " + this.currentUser.lastName;
    this.bookingPersonName.setValue(this.currentPersonName);

  }

  public openUploadDialog() {
    const modalRef = this.modalService.open(UploadDialogComponent);
    modalRef.result
      .then(result => {

        const dateString = new Date().toISOString().slice(0, 10);
        // modalRef.close();
        if (result) {
          console.log("defoooooooooooooooooo 1");
          this.imagesPath = result.imagesPath;
          console.log("defoooooooooooooooooo 2");
          this.imagesPath.forEach(element => {
            console.log("defoooooooooooooooooo 3");
            const url = "http://img.kabbalamma.org/content/" + dateString + "/" + element;
            console.log("defoooooooooooooooooo 4", url);
            this.displayImagesPath.push(url);
            console.log("defoooooooooooooooooo 5");
            this.addImages(url);
            console.log("finall******* 6", url);
          });
          console.log(this.websiteAlbumForm.value["imagesPath"]);
        }
      })
      .catch(error => {
        console.log(error);
      });
  }

  addImages(val) {
    let image_urls_control: any;
    image_urls_control = this.websiteAlbumForm.get("imageUrl");
    if (!image_urls_control.value.includes(val)) {
      image_urls_control.push(this.fb.control(val));
    }
  }

  addFiles() {
    this.file.nativeElement.click();
  }

  onFilesAdded() {
    const files: { [key: string]: File } = this.file.nativeElement.files;
    for (const key in files) {
      if (!isNaN(+key)) {
        const file_name = this.nx.utils.getUniqueFileName(1000000000, 9999999999) + '.' + files[key]['name'].split('.').pop();
        const blob = files[key].slice(0, files[key].size);
        const newFile = new File([blob], file_name);
        this.files.add(newFile);
        this.imagesPath.push(file_name);
        console.log(file_name);
        console.log(newFile);
        // this.files.add(files[key]); 
        // this.imagesPath.push(files[key]['name']);
      }
    }
  }

  closeDialog() {
    // if everything was uploaded already, just close the dialog
    if (this.uploadSuccessful) {
      const data = {
        imagesPath: this.imagesPath
      };
      //return this.dialogRef.close(data);
      return data;
    }

    // set the component state to "uploading"
    this.uploading = true;
    // start the upload and save the progress map
    console.log("progress Start");
    this.progress = this.uploadService.upload(this.files);
    console.log(this.progress);
    console.log("progress End");

    // convert the progress map into an array
    const allProgressObservables = [];
    for (const key in this.progress) {
      if (this.progress.hasOwnProperty(key)) {
        allProgressObservables.push(this.progress[key].progress);
      }
    }

    console.log("allProgressObservables");
    console.log(allProgressObservables);
    // for (const key in this.progress) {
    //     allProgressObservables.push(this.progress[key].progress);
    // }

    // Adjust the state variables

    // The OK-button should have the text "Finish" now
    this.primaryButtonText = "Finish";

    // The dialog should not be closed while uploading
    this.canBeClosed = false;
    // this.dialogRef.disableClose = true;

    // Hide the cancel-button
    this.showCancelButton = false;
    // When all progress-observables are completed...
    forkJoin(allProgressObservables).subscribe(end => {
      console.log("forkJoin");
      // ... the dialog can be closed again...
      this.canBeClosed = true;
      // this.dialogRef.disableClose = false;

      // ... the upload was successful...
      this.uploadSuccessful = true;

      // ... and the component is no longer uploading
      this.uploading = false;
    });
  }


 

  get userId() {
    return this.websiteAlbumForm.get("userId");
  }
  get bookingPersonName() {
    return this.websiteAlbumForm.get("bookingPersonName");
  }
  get albumName() {
    return this.websiteAlbumForm.get("albumName");
  }
  get imageUrl() {
    return this.websiteAlbumForm.get("imageUrl") as FormArray;
  }



  onSubmitForm() {
    if (!this.websiteAlbumForm.valid) {
      this.validateForm(this.websiteAlbumForm);
    } else if (this.displayImagesPath.length <= 0) {
      this.imageAdded = true;
      this.validateForm(this.websiteAlbumForm);
    } else if (this.websiteAlbumForm.valid) {
      const req = {
        url: AppConfig.Api.WebsiteAlbum.Create,
        params: this.websiteAlbumForm.value
      };
      this.ds.post(req).subscribe((res: any) => {
        if (res.status) {
          this.nx.message.success("Add Website Album Successfully.");
          this.onResetForm();
        } else {
          this.nx.message.error(res.message);
        }
      });
    }
  }

  onResetForm() {
    this.websiteAlbumForm.reset();
    this.onRouteChange('admin/website-album/list');
  }

  onRouteChange(path) {
    this.router.navigate([path]);
  }

  private initializeForm() {
    this.websiteAlbumForm = this.fb.group({
      userId: "",
      bookingPersonName: "N/A",
      albumName: ["", Validators.required],
      imageUrl: this.fb.array([]),
    });
  }

  private validateForm(formGroup: FormGroup) {
    Object.keys(formGroup.controls).forEach(filed => {
      const control = formGroup.get(filed);
      if (control instanceof FormControl) {
        control.markAsTouched({ onlySelf: true });
      }
    });
  }

}
