  onfilterType(idType) {
    this.filterCollection = [];
    let _idType = idType;

    this.collection.forEach(element => {
      if (_idType == element.utsavatype) {
        this.filterCollection.push(element);
        //console.log(element);
      }
    });

    this.filterCollection.sort((a, b) => (a.utsavaMurthyNumber > b.utsavaMurthyNumber) ? 1 : ((b.utsavaMurthyNumber > a.utsavaMurthyNumber) ? -1 : 0));

    //console.log(_idType);
    this.countTotal(this.filterCollection, _idType);
    this.getRange(this.filterCollection, _idType);
  }

  onfilterTypeBooking(idType) {
    this.filterCollectionBooking = [];
    let _idType = idType;

    this.collectionBooking.forEach(element => {
      if (element.bookingFor == "seva") {
        if (_idType == element.sevaType._id) {
          this.filterCollectionBooking.push(element);
          // console.log(element);
        }
      } else if (element.bookingFor == "darshan") {
        if (_idType == element.darshanType._id) {
          this.filterCollectionBooking.push(element);
          // console.log(element);
        }
      }
    });

    this.filterCollectionBooking.sort((a, b) => (a.bookingNumber > b.bookingNumber) ? 1 : ((b.bookingNumber > a.bookingNumber) ? -1 : 0));

    //console.log(_idType);
    this.countTotal(this.filterCollectionBooking, _idType);
    this.getRange(this.filterCollectionBooking, _idType);
  }

