import { Component, OnInit } from "@angular/core";
import { Router } from "@angular/router";
import { DataService } from "../../../shared/services/data.service";
import { AppConfig } from "../../../app.config";
import { PageModel } from "../../../models/page.model";
import { NgbModal } from "@ng-bootstrap/ng-bootstrap";
import { ConfirmBoxComponent } from "../../common/confirm-box/confirm-box.component";

@Component({
  selector: "app-donation-type",
  templateUrl: "./donation-type.component.html",
  styleUrls: ["./donation-type.component.css"]
})
export class DonationTypeComponent implements OnInit {
  donationTypeList: any[] = [];
  page: PageModel = new PageModel("firstName");

  constructor(
    private router: Router,
    private modalService: NgbModal,
    private ds: DataService
  ) {}

  ngOnInit() {
    this.getDonationTypeList();
  }

  onRouteChange(path) {
    this.router.navigate([path]);
  }

  onAddClick() {
    this.onRouteChange("admin/donation-type/add");
  }

  onEditClick(item: any) {
    this.onRouteChange("admin/donation-type/edit/" + item._id);
  }

  onDeleteConfirm(item: any) {

    const modalRef = this.modalService.open(ConfirmBoxComponent);
    modalRef.componentInstance.modelData = {
      message: "Are you sure you want to delete?"
    };
    modalRef.result
      .then(result => {
        if (result) {
          this.onDelete(item._id);
        }
      })
      .catch(error => {
        console.log(error);
      });
  }

  onDelete(id: any) {
    const req = {
      url: AppConfig.Api.DonationType.Delete,
      params: { id: id }
    };
    this.ds.post(req).subscribe((res: any) => {
      if (res.status) {
        this.removeItemFromList(id);
      } else {
      }
    });
  }

  removeItemFromList(id) {
    const index = this.donationTypeList.findIndex(tm => tm._id === id);
    this.donationTypeList.splice(index);
  }

  onSort(item) {}

  private getDonationTypeList() {
    const req = {
      url: AppConfig.Api.DonationType.GetAll,
      params: {
        currentPage: this.page.currentPage,
        itemPerPage: this.page.itemPerPage,
        sort: this.page.sort,
        sortBy: this.page.sortBy
      }
    };
    this.ds.post(req).subscribe((res: any) => {
      if (res.status) {
        this.donationTypeList = res.data;
        this.page.totalItems = res.totalItems;
      } else {
      }
    });
  }
}
