import { Component, OnInit, Input, Output, EventEmitter } from '@angular/core';

@Component({
  selector: 'app-nxd-pagination',
  templateUrl: './nxd-pagination.component.html',
  styleUrls: ['./nxd-pagination.component.css']
})
export class NxdPaginationComponent implements OnInit {

  itemPerPageList: any[] = [5, 10, 20, 50, 100];
  displayPageCount: number;
  selectedItem: number;

  @Input() itemPerPage: number;
  @Input() totalItems: number;
  @Input() currentPage: number;

  @Output() onPageSelect = new EventEmitter<number>();
  @Output() onSelectItemPerPage = new EventEmitter<number>();
  @Output() onPreviousPageSelect = new EventEmitter<boolean>();
  @Output() onNextPageSelect = new EventEmitter<boolean>();

  constructor() { }

  ngOnInit() {
    this.displayPageCount = 5;
    this.selectedItem = this.itemPerPage;
  }

  onChangeItemPerPage(value: any) {
    this.currentPage = 1;
    this.itemPerPage = +value;
    this.onSelectItemPerPage.next(this.itemPerPage);
  }

  getDisplayPages(): Number[] {
    const pages: Number[] = [];
    const pageCount = Math.ceil(this.totalItems / this.itemPerPage);
    pages.push(this.currentPage);
    for (let index = 0; index < this.displayPageCount; index++) {

      if (pages.length < this.displayPageCount) {
        if (Math.min.apply(null, pages) > 1) {
          pages.push(Math.min.apply(null, pages) - 1);
        }
      }
      if (pages.length < this.displayPageCount) {
        if (Math.max.apply(null, pages) < pageCount) {
          pages.push(Math.max.apply(null, pages) + 1);
        }
      }

    }
    pages.sort((a: number, b: number) => a - b);
    return pages;
  }

  onPreClick() {
    this.onPreviousPageSelect.next(true);
  }

  onSelectPage(currentPage: number) {
    this.onPageSelect.next(currentPage);
  }

  onNextClick() {
    this.onNextPageSelect.next(true);
  }

  lastPage() {
    return this.itemPerPage * this.currentPage > this.totalItems;
  }

}
