


import { Component, OnInit } from "@angular/core";
import { DataService } from "./../../../../shared/services/data.service";
import { AppConfig } from "./../../../../app.config";
import { PageModel } from "./../../../../models/page.model";
import { Router } from "@angular/router";
import { NgbModal, ModalDismissReasons } from "@ng-bootstrap/ng-bootstrap";
import { ViewSpecialPoojaComponent } from "./../view-special-pooja/view-special-pooja.component";
import { NxService } from "./../../../../shared/nx-library/nx.service";

@Component({
  selector: 'app-list-special-pooja',
  templateUrl: './list-special-pooja.component.html',
  styleUrls: ['./list-special-pooja.component.css']
})
export class ListSpecialPoojaComponent implements OnInit {
  kanikeList: any[] = [];
  page: PageModel = new PageModel("firstName");
  searchText: string;

  constructor(
    private router: Router,
    private ds: DataService,
    private modalService: NgbModal,
    private nx: NxService
  ) {}

  ngOnInit() {
    this.getSpecialPoojaList();
  }

  onRouteChange(path) {
    this.router.navigate([path]);
  }

  onSort(item) {}



  onViewDetails(item) {
    const modalRef = this.modalService.open(ViewSpecialPoojaComponent, {
      size: "lg"
    });
    modalRef.componentInstance.modelData = item;
    modalRef.result
      .then(result => {
        if (result) {
          console.log("Hello");
        }
      })
      .catch(error => {
        console.log(error);
      });
  }

  private getSpecialPoojaList() {
    const req = {
      url: AppConfig.Api.SpecialPooja.GetAll,
      params: {
        currentPage: this.page.currentPage,
        itemPerPage: this.page.itemPerPage,
        sort: this.page.sort,
        sortBy: this.page.sortBy
      }
    };
    this.ds.post(req).subscribe((res: any) => {
      if (res.status) {
        this.getSpecialPoojaList = res.data.collection;
        this.page.totalItems = res.totalItems;
      } else {
      }
    });
  }

  onChangeItemPerPage(value: any) {
    this.page.currentPage = 1;
    this.page.itemPerPage = +value;
    this.getSpecialPoojaList();
  }
}
