import { Component, OnInit } from "@angular/core";
import { Router } from "@angular/router";
import {
  FormGroup,
  FormBuilder,
  FormControl,
  Validators
} from "@angular/forms";
import { DataService } from "../../../../shared/services/data.service";
import { NxService } from "../../../../shared/nx-library/nx.service";
import { AppConfig } from "../../../../app.config";

@Component({
  selector: 'app-add-seva-type',
  templateUrl: './add-seva-type.component.html',
  styleUrls: ['./add-seva-type.component.css']
})
export class AddSevaTypeComponent implements OnInit {

  sevaTypeForm: FormGroup;
  vm = AppConfig.Message.Validation;
  constructor(
    private fb: FormBuilder,
    private ds: DataService,
    private router: Router,
    private nx: NxService
  ) {
    this.initializeForm();
  }

  ngOnInit() {}

  onSubmitForm() {
    if (!this.sevaTypeForm.valid) {
      this.validateForm(this.sevaTypeForm);
    } else if (this.sevaTypeForm.valid) {
      const req = {
        url: AppConfig.Api.SevaType.Create,
        params: this.sevaTypeForm.value
      };
      this.ds.post(req).subscribe((res: any) => {
        if (res.status) {
          this.nx.message.success("Add Seva Type Successfully.");
          this.onResetForm();
        } else {
          this.nx.message.error(res.message);
        }
      });
    }
  }

  onResetForm() {
    this.sevaTypeForm.reset();
    this.onRouteChange('admin/seva-type');
  }

  onRouteChange(path) {
    this.router.navigate([path]);
  }

  get title() {
    return this.sevaTypeForm.get("title");
  }

  get price() {
    return this.sevaTypeForm.get("price");
  }

  get allowed() {
    return this.sevaTypeForm.get("allowed");
  }

  get description() {
    return this.sevaTypeForm.get("description");
  }

  private initializeForm() {
    this.sevaTypeForm = this.fb.group({
      title: ["", Validators.required],
      price: [0, Validators.required],
      allowed: [0, Validators.required],
      description: ""
    });
  }

  private validateForm(formGroup: FormGroup) {
    Object.keys(formGroup.controls).forEach(filed => {
      const control = formGroup.get(filed);
      if (control instanceof FormControl) {
        control.markAsTouched({ onlySelf: true });
      }
    });
  }

}
