import { Component, OnInit } from "@angular/core";
import { Router } from "@angular/router";
import {
  FormGroup,
  FormBuilder,
  Validators,
  FormControl
} from "@angular/forms";
import { NxService } from "../../../shared/nx-library/nx.service";
import { DataService } from "../../../shared/services/data.service";
import { AppConfig } from "../../../app.config";

@Component({
  selector: "app-my-profile",
  templateUrl: "./my-profile.component.html",
  styleUrls: ["./my-profile.component.css"]
})
export class MyProfileComponent implements OnInit {
  registerForm: FormGroup;
  currentUser: any;
  displayName: string;
  // vm = AppConfig.Message.Validation;
  constructor(
    private fb: FormBuilder,
    private ds: DataService,
    private router: Router,
    private nx: NxService
  ) {
    this.initializeForm();
  }

  ngOnInit() {
    const currentUser = localStorage.getItem("current-user");
    this.currentUser = JSON.parse(currentUser);
    this.displayName =
      this.currentUser.firstName + " " + this.currentUser.lastName;
    this.setFormData(this.currentUser);
  }

  onSubmitForm() {
    if (!this.registerForm.valid) {
      this.validateForm(this.registerForm);
    } else if (this.registerForm.valid) {
      const req = {
        url: AppConfig.Api.User.Update,
        params: this.registerForm.value
      };
      this.ds.post(req).subscribe((res: any) => {
        if (res.status) {
          this.setFormData(res.data);
          this.nx.message.success(res.message);
        } else {
          this.nx.message.error(res.message);
        }
      });
    }
  }

  onRouteChange(path) {
    this.router.navigate([path]);
  }

  resetForm() {
    this.registerForm.reset();
  }

  get firstName() {
    return this.registerForm.get("firstName");
  }
  get lastName() {
    return this.registerForm.get("lastName");
  }
  get email() {
    return this.registerForm.get("email");
  }

  private initializeForm() {
    this.registerForm = this.fb.group({
      _id: ["", Validators.required],
      firstName: ["", Validators.required],
      lastName: ["", Validators.required],
      email: ["", Validators.required]
    });
  }

  private validateForm(formGroup: FormGroup) {
    Object.keys(formGroup.controls).forEach(filed => {
      const control = formGroup.get(filed);
      if (control instanceof FormControl) {
        control.markAsTouched({ onlySelf: true });
      }
    });
  }

  private setFormData(model: any) {
    this.registerForm.patchValue({
      _id: model._id,
      firstName: model.firstName,
      lastName: model.lastName,
      email: model.email
    });
  }
}
