import { Component, OnInit } from "@angular/core";
import { Router } from "@angular/router";
import {
  FormGroup,
  FormBuilder,
  FormControl,
  Validators
} from "@angular/forms";
import { DataService } from "../../../../shared/services/data.service";
import { NxService } from "../../../../shared/nx-library/nx.service";
import { AppConfig } from "../../../../app.config";

@Component({
  selector: "app-add-darshan-type",
  templateUrl: "./add-darshan-type.component.html",
  styleUrls: ["./add-darshan-type.component.css"]
})
export class AddDarshanTypeComponent implements OnInit {
  darshanTypeForm: FormGroup;
  vm = AppConfig.Message.Validation;
  constructor(
    private fb: FormBuilder,
    private ds: DataService,
    private router: Router,
    private nx: NxService
  ) {
    this.initializeForm();
  }

  ngOnInit() {}

  onSubmitForm() {
    if (!this.darshanTypeForm.valid) {
      this.validateForm(this.darshanTypeForm);
    } else if (this.darshanTypeForm.valid) {
      const req = {
        url: AppConfig.Api.DarshanType.Create,
        params: this.darshanTypeForm.value
      };
      this.ds.post(req).subscribe((res: any) => {
        if (res.status) {
          this.nx.message.success("Add Darshan Type Successfully.");
          this.onResetForm();
        } else {
          this.nx.message.error(res.message);
        }
      });
    }
  }

  onResetForm() {
    this.darshanTypeForm.reset();
    this.onRouteChange('admin/darshan-type');
  }

  onRouteChange(path) {
    this.router.navigate([path]);
  }

  get title() {
    return this.darshanTypeForm.get("title");
  }

  get price() {
    return this.darshanTypeForm.get("price");
  }

  get allowed() {
    return this.darshanTypeForm.get("allowed");
  }

  get description() {
    return this.darshanTypeForm.get("description");
  }

  private initializeForm() {
    this.darshanTypeForm = this.fb.group({
      title: ["", Validators.required],
      price: [0, Validators.required],
      allowed: [0, Validators.required],
      description: ""
    });
  }

  private validateForm(formGroup: FormGroup) {
    Object.keys(formGroup.controls).forEach(filed => {
      const control = formGroup.get(filed);
      if (control instanceof FormControl) {
        control.markAsTouched({ onlySelf: true });
      }
    });
  }
}
